import { useEffect, useState } from "react";
import { Navigate } from "react-router-dom";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/integrations/supabase/client";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter,
} from "@/components/ui/dialog";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { UserCog, Plus, Trash2, KeyRound, Pencil } from "lucide-react";

interface AdminUser {
  id: string;
  email: string;
  full_name: string | null;
  branch_id: string | null;
  roles: string[];
  created_at: string;
  last_sign_in_at: string | null;
}

const fnUrl = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/admin-users`;

async function call(method: string, body?: any) {
  const { data: { session } } = await supabase.auth.getSession();
  const res = await fetch(fnUrl, {
    method,
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${session?.access_token ?? ""}`,
      apikey: import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY,
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  const json = await res.json();
  if (!res.ok) throw new Error(json.error ?? "Request failed");
  return json;
}

export default function AdminUsers() {
  const { role, loading, user: me } = useAuth();
  const [users, setUsers] = useState<AdminUser[] | null>(null);
  const [branches, setBranches] = useState<{ id: string; name: string; code: string }[]>([]);
  const [createOpen, setCreateOpen] = useState(false);
  const [editing, setEditing] = useState<AdminUser | null>(null);
  const [busy, setBusy] = useState(false);

  // Create form
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [fullName, setFullName] = useState("");
  const [newRole, setNewRole] = useState<"admin" | "branch_user">("branch_user");
  const [branchId, setBranchId] = useState<string>("");

  // Edit form
  const [eName, setEName] = useState("");
  const [eRole, setERole] = useState<"admin" | "branch_user">("branch_user");
  const [eBranch, setEBranch] = useState<string>("");
  const [ePassword, setEPassword] = useState("");

  const reload = async () => {
    // Fetch branches independently to ensure they load even if users fetch is slow/fails
    supabase.from("branches").select("id, name, code").order("name")
      .then(({ data, error }) => {
        if (error) {
          console.error("Error fetching branches:", error);
          toast.error("Failed to load branches");
        } else {
          setBranches(data ?? []);
        }
      });

    try {
      const res = await call("GET");
      setUsers(res.users);
    } catch (e: any) {
      console.error("Reload error:", e);
      const msg = e.message === "Failed to fetch" 
        ? "Edge Function not reachable. Please ensure 'admin-users' function is deployed: npx supabase functions deploy admin-users"
        : e.message;
      toast.error("Failed to load users: " + msg);
      setUsers([]); // Set to empty array to stop loading skeleton
    }
  };

  useEffect(() => { if (role === "admin") reload(); }, [role]);

  if (loading) return <div className="p-8"><Skeleton className="h-32" /></div>;
  if (role !== "admin") return <Navigate to="/" replace />;

  const submitCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 6) { toast.error("Password min 6 chars"); return; }
    if (newRole === "branch_user" && !branchId) { toast.error("Select a branch"); return; }
    setBusy(true);
    try {
      await call("POST", {
        email: email.trim(), password, full_name: fullName.trim() || null,
        role: newRole, branch_id: newRole === "branch_user" ? branchId : null,
      });
      toast.success("User created");
      setCreateOpen(false);
      setEmail(""); setPassword(""); setFullName(""); setNewRole("branch_user"); setBranchId("");
      reload();
    } catch (e: any) { toast.error(e.message); }
    setBusy(false);
  };

  const openEdit = (u: AdminUser) => {
    setEditing(u);
    setEName(u.full_name ?? "");
    setERole((u.roles[0] as any) ?? "branch_user");
    setEBranch(u.branch_id ?? "");
    setEPassword("");
  };

  const submitEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editing) return;
    if (eRole === "branch_user" && !eBranch) { toast.error("Select a branch"); return; }
    setBusy(true);
    try {
      await call("PATCH", {
        id: editing.id,
        full_name: eName.trim() || null,
        branch_id: eRole === "branch_user" ? eBranch : null,
        role: eRole,
        password: ePassword || undefined,
      });
      toast.success("Updated");
      setEditing(null);
      reload();
    } catch (e: any) { toast.error(e.message); }
    setBusy(false);
  };

  const remove = async (u: AdminUser) => {
    if (u.id === me?.id) { toast.error("You can't delete yourself"); return; }
    if (!confirm(`Delete ${u.email}? This cannot be undone.`)) return;
    try { await call("DELETE", { id: u.id }); toast.success("Deleted"); reload(); }
    catch (e: any) { toast.error(e.message); }
  };

  const branchName = (id: string | null) => branches.find((b) => b.id === id)?.name ?? "—";

  return (
    <div className="p-4 md:p-8 max-w-6xl mx-auto space-y-6">
      <div className="flex items-end justify-between gap-4 flex-wrap">
        <div>
          <div className="text-xs uppercase tracking-wider text-muted-foreground">Admin</div>
          <h1 className="font-display text-3xl md:text-4xl font-bold flex items-center gap-2">
            <UserCog className="w-7 h-7 text-primary" /> User Management
          </h1>
        </div>

        <Dialog open={createOpen} onOpenChange={setCreateOpen}>
          <DialogTrigger asChild>
            <Button className="gradient-primary text-primary-foreground"><Plus className="w-4 h-4 mr-1" /> New User</Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader><DialogTitle>Create user</DialogTitle></DialogHeader>
            <form onSubmit={submitCreate} className="space-y-3">
              <div className="space-y-1.5"><Label>Full name</Label><Input value={fullName} onChange={(e) => setFullName(e.target.value)} /></div>
              <div className="space-y-1.5"><Label>Email</Label><Input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} /></div>
              <div className="space-y-1.5"><Label>Password</Label><Input type="text" required minLength={6} value={password} onChange={(e) => setPassword(e.target.value)} /></div>
              <div className="space-y-1.5">
                <Label>Role</Label>
                <Select value={newRole} onValueChange={(v: any) => setNewRole(v)}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="admin">Admin</SelectItem>
                    <SelectItem value="branch_user">Branch User</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              {newRole === "branch_user" && (
                <div className="space-y-1.5">
                  <Label>Branch</Label>
                  <Select value={branchId} onValueChange={setBranchId}>
                    <SelectTrigger><SelectValue placeholder="Select branch" /></SelectTrigger>
                    <SelectContent>
                      {branches.length === 0 ? (
                        <div className="p-2 text-sm text-muted-foreground text-center">No branches found. Please add branches first.</div>
                      ) : (
                        branches.map((b) => <SelectItem key={b.id} value={b.id}>{b.name} ({b.code})</SelectItem>)
                      )}
                    </SelectContent>
                  </Select>
                </div>
              )}
              <DialogFooter>
                <Button type="submit" disabled={busy} className="gradient-primary text-primary-foreground">Create</Button>
              </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <Card className="glass overflow-hidden">
        {!users ? <Skeleton className="h-40 m-4" /> : users.length === 0 ? (
          <div className="p-12 text-center text-muted-foreground text-sm">No users.</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-muted/40">
                <tr className="text-xs text-muted-foreground uppercase tracking-wider">
                  <th className="text-left font-medium px-4 py-3">User</th>
                  <th className="text-left font-medium px-4 py-3">Role</th>
                  <th className="text-left font-medium px-4 py-3">Branch</th>
                  <th className="text-left font-medium px-4 py-3 hidden md:table-cell">Last sign-in</th>
                  <th className="text-right font-medium px-4 py-3"></th>
                </tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id} className="border-t border-border/50 hover:bg-muted/30">
                    <td className="px-4 py-3">
                      <div className="font-medium">{u.full_name ?? "—"}</div>
                      <div className="text-xs text-muted-foreground">{u.email}{u.id === me?.id && <span className="ml-1 text-primary">(you)</span>}</div>
                    </td>
                    <td className="px-4 py-3">
                      {u.roles.map((r) => (
                        <Badge key={r} variant={r === "admin" ? "default" : "secondary"} className="mr-1">{r}</Badge>
                      ))}
                    </td>
                    <td className="px-4 py-3">{branchName(u.branch_id)}</td>
                    <td className="px-4 py-3 hidden md:table-cell text-xs text-muted-foreground">
                      {u.last_sign_in_at ? new Date(u.last_sign_in_at).toLocaleString() : "Never"}
                    </td>
                    <td className="px-4 py-3 text-right">
                      <Button variant="ghost" size="icon" onClick={() => openEdit(u)}><Pencil className="w-4 h-4" /></Button>
                      <Button variant="ghost" size="icon" onClick={() => remove(u)} disabled={u.id === me?.id}>
                        <Trash2 className="w-4 h-4 text-destructive" />
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      <Dialog open={!!editing} onOpenChange={(o) => !o && setEditing(null)}>
        <DialogContent>
          <DialogHeader><DialogTitle>Edit user</DialogTitle></DialogHeader>
          {editing && (
            <form onSubmit={submitEdit} className="space-y-3">
              <div className="text-sm text-muted-foreground">{editing.email}</div>
              <div className="space-y-1.5"><Label>Full name</Label><Input value={eName} onChange={(e) => setEName(e.target.value)} /></div>
              <div className="space-y-1.5">
                <Label>Role</Label>
                <Select value={eRole} onValueChange={(v: any) => setERole(v)}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="admin">Admin</SelectItem>
                    <SelectItem value="branch_user">Branch User</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              {eRole === "branch_user" && (
                <div className="space-y-1.5">
                  <Label>Branch</Label>
                  <Select value={eBranch} onValueChange={setEBranch}>
                    <SelectTrigger><SelectValue placeholder="Select branch" /></SelectTrigger>
                    <SelectContent>
                      {branches.length === 0 ? (
                        <div className="p-2 text-sm text-muted-foreground text-center">No branches found. Please add branches first.</div>
                      ) : (
                        branches.map((b) => <SelectItem key={b.id} value={b.id}>{b.name} ({b.code})</SelectItem>)
                      )}
                    </SelectContent>
                  </Select>
                </div>
              )}
              <div className="space-y-1.5">
                <Label className="flex items-center gap-1"><KeyRound className="w-3 h-3" /> New password (optional)</Label>
                <Input type="text" minLength={6} value={ePassword} onChange={(e) => setEPassword(e.target.value)} placeholder="Leave blank to keep current" />
              </div>
              <DialogFooter>
                <Button type="submit" disabled={busy} className="gradient-primary text-primary-foreground">Save</Button>
              </DialogFooter>
            </form>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Wallet, ArrowRight, Sparkles } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card } from "@/components/ui/card";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";
import { z } from "zod";

const schema = z.object({
  email: z.string().trim().email("Invalid email").max(255),
  password: z.string().min(6, "Min 6 characters").max(72),
  fullName: z.string().trim().min(2).max(80).optional(),
});

export default function Auth() {
  const nav = useNavigate();
  const { user, loading } = useAuth();
  const [mode, setMode] = useState<"signin" | "signup">("signin");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [fullName, setFullName] = useState("");
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    if (!loading && user) nav("/", { replace: true });
  }, [user, loading, nav]);

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    const parsed = schema.safeParse({ email, password, fullName: mode === "signup" ? fullName : undefined });
    if (!parsed.success) {
      toast.error(parsed.error.issues[0].message);
      return;
    }
    setBusy(true);
    try {
      if (mode === "signin") {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        toast.success("Welcome back");
        nav("/", { replace: true });
      } else {
        const { error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            emailRedirectTo: `${window.location.origin}/`,
            data: { full_name: fullName },
          },
        });
        if (error) throw error;
        toast.success("Account created — signing you in");
        const { error: e2 } = await supabase.auth.signInWithPassword({ email, password });
        if (e2) throw e2;
        nav("/", { replace: true });
      }
    } catch (err: any) {
      toast.error(err.message ?? "Authentication failed");
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 gradient-hero relative overflow-hidden">
      <div className="absolute inset-0 opacity-30">
        <div className="absolute -top-24 -left-24 w-96 h-96 bg-accent/40 rounded-full blur-3xl animate-float" />
        <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-primary-glow/40 rounded-full blur-3xl animate-float" style={{ animationDelay: "1s" }} />
      </div>

      <div className="relative z-10 w-full max-w-md">
        <Link to="/" className="flex items-center justify-center gap-2 mb-8 text-primary-foreground">
          <div className="w-12 h-12 rounded-2xl gradient-accent flex items-center justify-center shadow-amber">
            <Wallet className="w-6 h-6 text-accent-foreground" />
          </div>
          <div>
            <h1 className="font-display text-2xl font-bold">AsaanKhata</h1>
            <p className="text-xs text-primary-foreground/70 -mt-0.5">Multi-branch accounting</p>
          </div>
        </Link>

        <Card className="glass p-8 animate-scale-in border-0">
          <div className="mb-6">
            <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-accent/10 text-accent-foreground text-xs font-medium mb-3">
              <Sparkles className="w-3 h-3" /> {mode === "signin" ? "Welcome back" : "Get started"}
            </div>
            <h2 className="font-display text-3xl font-bold tracking-tight">
              {mode === "signin" ? "Sign in" : "Create account"}
            </h2>
            <p className="text-sm text-muted-foreground mt-1">
              {mode === "signin" ? "Access your branch ledger" : "First account becomes admin"}
            </p>
          </div>

          <form onSubmit={submit} className="space-y-4">
            {mode === "signup" && (
              <div className="space-y-1.5">
                <Label htmlFor="name">Full name</Label>
                <Input id="name" value={fullName} onChange={(e) => setFullName(e.target.value)} placeholder="Ali Khan" />
              </div>
            )}
            <div className="space-y-1.5">
              <Label htmlFor="email">Email</Label>
              <Input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="you@company.com" required />
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="password">Password</Label>
              <Input id="password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" required />
            </div>
            <Button type="submit" disabled={busy} className="w-full gradient-primary text-primary-foreground hover:opacity-90 shadow-soft">
              {busy ? "Please wait..." : mode === "signin" ? "Sign in" : "Create account"}
              <ArrowRight className="w-4 h-4 ml-1" />
            </Button>
          </form>

          <div className="mt-6 text-center text-sm text-muted-foreground">
            {mode === "signin" ? "New here?" : "Already have an account?"}{" "}
            <button onClick={() => setMode(mode === "signin" ? "signup" : "signin")} className="text-primary font-medium hover:underline">
              {mode === "signin" ? "Create account" : "Sign in"}
            </button>
          </div>
        </Card>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowLeft, Building2, Wallet, Users, Receipt, TrendingUp, MapPin, Hash, Plus } from "lucide-react";
import { formatMoney } from "@/lib/format";
import { motion } from "framer-motion";

export default function BranchDetail() {
  const { id } = useParams();
  const [branch, setBranch] = useState<any | null>(null);
  const [accounts, setAccounts] = useState<any[] | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!id) return;
    (async () => {
      const [{ data: b }, { data: a }] = await Promise.all([
        supabase.from("branches").select("*").eq("id", id).maybeSingle(),
        supabase.from("accounts").select("*, transactions(debit, credit)").eq("branch_id", id),
      ]);
      setBranch(b);
      setAccounts(a ?? []);
      setLoading(false);
    })();
  }, [id]);

  if (loading) return <div className="p-8 space-y-4"><Skeleton className="h-12 w-1/4" /><Skeleton className="h-64" /></div>;
  if (!branch) return <div className="p-8 text-center text-muted-foreground">Branch not found.</div>;

  const stats = accounts?.reduce((acc: any, curr: any) => {
    const balance = curr.transactions?.reduce((sum: number, tx: any) => sum + (Number(tx.credit) - Number(tx.debit)), 0) || 0;
    if (!acc[curr.currency]) acc[curr.currency] = { count: 0, balance: 0 };
    acc[curr.currency].count++;
    acc[curr.currency].balance += balance;
    return acc;
  }, {}) || {};

  return (
    <div className="p-4 md:p-8 max-w-[1400px] mx-auto space-y-8 animate-in fade-in duration-500">
      <Link to="/branches" className="inline-flex items-center text-sm text-muted-foreground hover:text-foreground transition-colors group">
        <ArrowLeft className="w-4 h-4 mr-1 group-hover:-translate-x-1 transition-transform" /> Back to Branches
      </Link>

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 rounded-xl bg-primary/10 text-primary">
              <Building2 className="w-6 h-6" />
            </div>
            <Badge variant="outline" className="font-mono uppercase tracking-tighter">{branch.code}</Badge>
          </div>
          <h1 className="font-display text-4xl font-extrabold tracking-tight">{branch.name}</h1>
          <p className="text-muted-foreground mt-2 flex items-center gap-1.5">
             <MapPin className="w-3.5 h-3.5" /> Established Business Unit
          </p>
        </motion.div>

        <div className="grid grid-cols-2 gap-4">
          {Object.entries(stats).map(([curr, data]: [string, any]) => (
            <Card key={curr} className="glass p-4 border-l-4 border-l-primary/40">
              <div className="text-[10px] uppercase tracking-widest text-muted-foreground font-bold mb-1">{curr} Net Liquidity</div>
              <div className={`font-display font-bold text-xl num ${data.balance >= 0 ? "text-success" : "text-destructive"}`}>
                {formatMoney(data.balance, curr as any)}
              </div>
            </Card>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="glass p-6">
          <div className="flex items-center gap-3 mb-4 text-primary">
            <Users className="w-5 h-5" />
            <h2 className="font-display font-bold">Branch Accounts</h2>
          </div>
          <div className="text-4xl font-display font-black mb-1">{accounts?.length || 0}</div>
          <p className="text-xs text-muted-foreground uppercase tracking-widest font-semibold">Total Registered Accounts</p>
        </Card>

        <Card className="glass p-6">
          <div className="flex items-center gap-3 mb-4 text-accent">
            <TrendingUp className="w-5 h-5" />
            <h2 className="font-display font-bold">Activity Status</h2>
          </div>
          <div className="text-4xl font-display font-black mb-1 text-success">Active</div>
          <p className="text-xs text-muted-foreground uppercase tracking-widest font-semibold">Real-time Synchronization</p>
        </Card>

        <Card className="glass p-6">
          <div className="flex items-center gap-3 mb-4 text-indigo-500">
            <Hash className="w-5 h-5" />
            <h2 className="font-display font-bold">Branch ID</h2>
          </div>
          <div className="text-sm font-mono text-muted-foreground break-all">{branch.id}</div>
          <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-semibold mt-2">System GUID Reference</p>
        </Card>
      </div>

      <Card className="glass overflow-hidden border-none shadow-2xl">
        <div className="p-5 border-b border-border/50 flex items-center justify-between bg-muted/20">
          <h2 className="font-display font-bold text-lg flex items-center gap-2">
            <Wallet className="w-5 h-5 text-primary" /> Branch Ledger Accounts
          </h2>
          <Link to="/accounts/new">
            <Button size="sm" className="gradient-primary text-primary-foreground shadow-lg shadow-primary/20">
              <Plus className="w-4 h-4 mr-1" /> New Account
            </Button>
          </Link>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-muted/40">
              <tr className="text-xs text-muted-foreground uppercase tracking-wider">
                <th className="text-left font-bold px-6 py-4">Account</th>
                <th className="text-left font-bold px-6 py-4">Currency</th>
                <th className="text-right font-bold px-6 py-4">Balance</th>
                <th className="px-6 py-4"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border/30">
              {accounts?.length === 0 ? (
                <tr><td colSpan={4} className="text-center py-12 text-muted-foreground">No accounts registered in this branch.</td></tr>
              ) : accounts?.map((acc) => {
                const balance = acc.transactions?.reduce((sum: number, tx: any) => sum + (Number(tx.credit) - Number(tx.debit)), 0) || 0;
                return (
                  <tr key={acc.id} className="hover:bg-muted/30 transition-colors group">
                    <td className="px-6 py-4">
                      <div className="font-bold text-base">{acc.name}</div>
                      <div className="text-xs font-mono text-muted-foreground uppercase">{acc.account_no}</div>
                    </td>
                    <td className="px-6 py-4">
                      <Badge variant="secondary" className="font-bold">{acc.currency}</Badge>
                    </td>
                    <td className={`px-6 py-4 text-right font-display font-bold text-lg num ${balance >= 0 ? "text-success" : "text-destructive"}`}>
                      {formatMoney(balance, acc.currency)}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <Link to={`/accounts/${acc.id}`}>
                        <Button variant="ghost" size="sm" className="opacity-0 group-hover:opacity-100 transition-opacity">
                          View Ledger <ArrowLeft className="w-3 h-3 ml-1 rotate-180" />
                        </Button>
                      </Link>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { Navigate, Link } from "react-router-dom";
import { toast } from "sonner";
import { Building2, Plus, Trash2, MapPin, Hash, Briefcase } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { motion } from "framer-motion";

export default function Branches() {
  const { role, loading } = useAuth();
  const [rows, setRows] = useState<any[] | null>(null);
  const [name, setName] = useState("");
  const [code, setCode] = useState("");
  const [busy, setBusy] = useState(false);

  const reload = () => supabase.from("branches").select("*").order("name").then(({ data }) => setRows(data ?? []));
  useEffect(() => { reload(); }, []);

  if (loading) return <div className="p-8 max-w-4xl mx-auto space-y-4"><Skeleton className="h-12 w-1/3" /><Skeleton className="h-40 w-full" /></div>;
  if (role !== "admin") return <Navigate to="/" replace />;

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (name.trim().length < 2) { toast.error("Branch name must be at least 2 characters"); return; }
    if (code.trim().length < 1) { toast.error("Branch code is required"); return; }

    setBusy(true);
    const { error } = await supabase.from("branches").insert([{ 
      name: name.trim(), 
      code: code.trim().toUpperCase() 
    }]);
    setBusy(false);

    if (error) {
      if (error.code === "23505") toast.error("A branch with this code already exists");
      else toast.error(error.message);
      return;
    }

    toast.success("New branch established successfully");
    setName(""); setCode(""); reload();
  };

  const remove = async (id: string) => {
    if (!confirm("Are you sure? This will fail if there are accounts linked to this branch.")) return;
    const { error } = await supabase.from("branches").delete().eq("id", id);
    if (error) {
      toast.error("Cannot delete: Branch has active accounts or transactions.");
      return;
    }
    toast.success("Branch removed");
    reload();
  };

  return (
    <div className="p-4 md:p-8 max-w-5xl mx-auto space-y-8">
      <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
        <div className="text-xs uppercase tracking-widest text-primary font-bold mb-1">Administrative Tools</div>
        <h1 className="font-display text-4xl md:text-5xl font-bold tracking-tight flex items-center gap-3">
          <div className="p-2 rounded-2xl bg-primary/10 text-primary">
            <Building2 className="w-8 h-8" />
          </div>
          Network <span className="text-gradient">Branches</span>
        </h1>
        <p className="text-muted-foreground mt-2">Manage your business locations and their unique identification codes.</p>
      </motion.div>

      <div className="grid lg:grid-cols-3 gap-8 items-start">
        {/* Creation Form */}
        <Card className="glass p-6 lg:col-span-1 sticky top-20">
          <h2 className="font-display text-xl font-bold mb-4 flex items-center gap-2">
            <Plus className="w-5 h-5 text-accent" /> Add New Branch
          </h2>
          <form onSubmit={submit} className="space-y-4">
            <div className="space-y-2">
              <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Branch Name</Label>
              <div className="relative">
                <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input 
                  value={name} 
                  onChange={(e) => setName(e.target.value)} 
                  placeholder="e.g. Lahore Gulberg" 
                  className="pl-10"
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Branch Code</Label>
              <div className="relative">
                <Hash className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input 
                  value={code} 
                  onChange={(e) => setCode(e.target.value)} 
                  placeholder="e.g. LHR-01" 
                  className="pl-10 font-mono"
                  maxLength={10}
                />
              </div>
            </div>
            <Button type="submit" disabled={busy} className="w-full gradient-primary text-primary-foreground shadow-soft py-6 text-base font-semibold">
              {busy ? "Establishing..." : "Establish Branch"}
            </Button>
          </form>
        </Card>

        {/* Branches List */}
        <div className="lg:col-span-2 space-y-4">
          {!rows ? (
            <div className="space-y-3">
              {[...Array(3)].map((_, i) => <Skeleton key={i} className="h-20 w-full" />)}
            </div>
          ) : rows.length === 0 ? (
            <div className="glass p-12 text-center rounded-3xl">
              <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center mx-auto mb-4">
                <Building2 className="w-8 h-8 text-muted-foreground" />
              </div>
              <h3 className="font-display font-bold text-lg">No Branches Defined</h3>
              <p className="text-muted-foreground text-sm max-w-xs mx-auto mt-1">Start by adding your first business location using the form on the left.</p>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 gap-4">
              {rows.map((b, i) => (
                <motion.div 
                  key={b.id} 
                  initial={{ opacity: 0, scale: 0.95 }} 
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: i * 0.05 }}
                >
                  <Link to={`/branches/${b.id}`}>
                    <Card className="glass p-5 group hover:shadow-lg transition-all relative overflow-hidden border-l-4 border-l-transparent hover:border-l-primary">
                      <div className="absolute -right-4 -bottom-4 w-20 h-20 bg-primary/5 rounded-full group-hover:bg-primary/10 transition-colors" />
                      <div className="flex justify-between items-start relative">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="text-[10px] font-bold px-1.5 py-0.5 rounded bg-primary/10 text-primary uppercase font-mono tracking-tighter">
                              {b.code}
                            </span>
                          </div>
                          <h3 className="font-display font-bold text-xl">{b.name}</h3>
                          <div className="flex items-center gap-1.5 text-xs text-muted-foreground mt-2">
                            <Briefcase className="w-3 h-3" />
                            <span>Active Branch • Click to view</span>
                          </div>
                        </div>
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          onClick={(e) => { e.preventDefault(); remove(b.id); }}
                          className="opacity-0 group-hover:opacity-100 transition-opacity text-destructive hover:bg-destructive/10"
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    </Card>
                  </Link>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Wallet, Users, ArrowDownLeft, ArrowUpRight, Plus, Receipt, FileBarChart, TrendingUp, Building2, Lock } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { Link } from "react-router-dom";
import { Skeleton } from "@/components/ui/skeleton";
import { formatMoney, balanceLabel } from "@/lib/format";
import { motion } from "framer-motion";

interface Stats {
  accounts: number;
  branches: number;
  netPKR: number;
  netAED: number;
  todayDebit: number;
  todayCredit: number;
  byBranch: { name: string; pkr: number; aed: number; accounts: number }[];
}

export default function Dashboard() {
  const { profile, role } = useAuth();
  const [stats, setStats] = useState<Stats | null>(null);
  const [recent, setRecent] = useState<any[]>([]);

  useEffect(() => {
    (async () => {
      const today = new Date().toISOString().slice(0, 10);
      const [{ data: accounts }, { data: branches }, { data: txns }, { data: recentTx }] = await Promise.all([
        supabase.from("accounts").select("id, currency, branch_id, branches(name)"),
        supabase.from("branches").select("id, name"),
        supabase.from("transactions").select("debit, credit, txn_date, account_id, accounts(currency, branch_id)"),
        supabase.from("transactions").select("id, txn_code, txn_date, details, debit, credit, accounts(name, account_no, currency)").order("created_at", { ascending: false }).limit(8),
      ]);

      let netPKR = 0, netAED = 0, todayDebit = 0, todayCredit = 0;
      const branchMap: Record<string, { name: string; pkr: number; aed: number; accounts: number }> = {};
      (branches ?? []).forEach((b: any) => (branchMap[b.id] = { name: b.name, pkr: 0, aed: 0, accounts: 0 }));
      (accounts ?? []).forEach((a: any) => { if (branchMap[a.branch_id]) branchMap[a.branch_id].accounts++; });
      (txns ?? []).forEach((t: any) => {
        const d = Number(t.debit), c = Number(t.credit);
        const net = c - d;
        if (t.accounts?.currency === "PKR") netPKR += net;
        else netAED += net;
        if (t.txn_date === today) { todayDebit += d; todayCredit += c; }
        const bid = t.accounts?.branch_id;
        if (bid && branchMap[bid]) {
          if (t.accounts.currency === "PKR") branchMap[bid].pkr += net;
          else branchMap[bid].aed += net;
        }
      });

      setStats({
        accounts: accounts?.length ?? 0,
        branches: branches?.length ?? 0,
        netPKR, netAED, todayDebit, todayCredit,
        byBranch: Object.values(branchMap),
      });
      setRecent(recentTx ?? []);
    })();
  }, []);

  if (!stats) {
    return (
      <div className="p-6 space-y-4">
        <Skeleton className="h-12 w-1/3" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {[...Array(4)].map((_, i) => <Skeleton key={i} className="h-32" />)}
        </div>
      </div>
    );
  }

  const cards = [
    { label: "Total Accounts", value: stats.accounts.toString(), icon: Users, gradient: "from-primary to-primary-glow", sub: `${stats.branches} branches` },
    { label: "Net Balance (PKR)", value: formatMoney(stats.netPKR, "PKR"), icon: Wallet, gradient: "from-accent to-accent-glow", sub: balanceLabel(stats.netPKR), positive: stats.netPKR >= 0 },
    { label: "Net Balance (AED)", value: formatMoney(stats.netAED, "AED"), icon: TrendingUp, gradient: "from-emerald-600 to-teal-500", sub: balanceLabel(stats.netAED), positive: stats.netAED >= 0 },
    { label: "Today's Activity", value: formatMoney(stats.todayCredit + stats.todayDebit, ""), icon: Receipt, gradient: "from-indigo-600 to-violet-500", sub: `↓${formatMoney(stats.todayDebit, "")} ↑${formatMoney(stats.todayCredit, "")}` },
  ];

  return (
    <div className="p-4 md:p-8 space-y-8 max-w-[1600px] mx-auto">
      {/* Hero */}
      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }}>
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <div className="text-sm text-muted-foreground">{role === "admin" ? "Administrator" : "Branch User"} dashboard</div>
            <h1 className="font-display text-4xl md:text-5xl font-bold tracking-tight">
              Hello, <span className="text-gradient">{profile?.full_name?.split(" ")[0] ?? "there"}</span>
            </h1>
            <p className="text-muted-foreground mt-1">Here's what's happening across your ledger today.</p>
          </div>
          <div className="flex gap-2 flex-wrap">
            {role === "admin" && (
              <Link to="/branches"><Button variant="secondary" className="glass"><Building2 className="w-4 h-4 mr-1" /> Branches</Button></Link>
            )}
            <Link to="/accounts/new"><Button className="gradient-primary text-primary-foreground shadow-soft"><Plus className="w-4 h-4 mr-1" /> New Account</Button></Link>
            <Link to="/transactions/new"><Button variant="outline" className="border-2"><Receipt className="w-4 h-4 mr-1" /> New Transaction</Button></Link>
          </div>
        </div>

        {/* Access Debugger (Hidden from non-admins eventually, but shown now for troubleshooting) */}
        {!role && (
          <div className="mt-4 p-4 rounded-2xl bg-destructive/5 border border-destructive/20 text-destructive text-sm flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Lock className="w-4 h-4" />
              <span><strong>Access Limited:</strong> Your account does not have Admin privileges. Role: <strong>{role ?? "None"}</strong></span>
            </div>
            <div className="text-[10px] font-mono opacity-50">UID: {profile?.id}</div>
          </div>
        )}
      </motion.div>

      {/* Stat cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {cards.map((c, i) => (
          <motion.div key={c.label} initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.06 }}>
            <Card className="glass p-5 relative overflow-hidden group hover:shadow-lift transition-all">
              <div className={`absolute -top-10 -right-10 w-32 h-32 rounded-full bg-gradient-to-br ${c.gradient} opacity-20 blur-2xl group-hover:opacity-30 transition-opacity`} />
              <div className="relative">
                <div className="flex items-start justify-between mb-3">
                  <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${c.gradient} flex items-center justify-center shadow-soft`}>
                    <c.icon className="w-5 h-5 text-white" />
                  </div>
                </div>
                <div className="text-xs uppercase tracking-wider text-muted-foreground font-medium">{c.label}</div>
                <div className="text-2xl font-display font-bold mt-1 num">{c.value}</div>
                <div className={`text-xs mt-1 num ${c.positive === false ? "text-destructive" : c.positive === true ? "text-success" : "text-muted-foreground"}`}>{c.sub}</div>
              </div>
            </Card>
          </motion.div>
        ))}
      </div>

      {/* Branch breakdown + recent */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <Card className="glass p-6 lg:col-span-1">
          <div className="flex items-center gap-2 mb-4">
            <Building2 className="w-4 h-4 text-primary" />
            <h2 className="font-display font-semibold">Branch Summary</h2>
          </div>
          {stats.byBranch.length === 0 ? (
            <div className="text-sm text-muted-foreground py-8 text-center">
              No branches yet. {role === "admin" && <Link to="/branches" className="text-primary underline">Create one</Link>}
            </div>
          ) : (
            <div className="space-y-3">
              {stats.byBranch.map((b) => (
                <div key={b.name} className="p-3 rounded-xl bg-muted/40">
                  <div className="flex items-center justify-between">
                    <div className="font-medium">{b.name}</div>
                    <div className="text-xs text-muted-foreground">{b.accounts} accts</div>
                  </div>
                  <div className="grid grid-cols-2 gap-2 mt-2 text-xs num">
                    <div>
                      <div className="text-muted-foreground">PKR</div>
                      <div className={b.pkr >= 0 ? "text-success font-semibold" : "text-destructive font-semibold"}>
                        {formatMoney(b.pkr, "PKR")} {balanceLabel(b.pkr)}
                      </div>
                    </div>
                    <div>
                      <div className="text-muted-foreground">AED</div>
                      <div className={b.aed >= 0 ? "text-success font-semibold" : "text-destructive font-semibold"}>
                        {formatMoney(b.aed, "AED")} {balanceLabel(b.aed)}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </Card>

        <Card className="glass p-6 lg:col-span-2">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
