      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";
import { ArrowLeft } from "lucide-react";
import { z } from "zod";

const schema = z.object({
  name: z.string().trim().min(2).max(100),
  mobile: z.string().trim().max(20).optional().or(z.literal("")),
  address: z.string().trim().max(300).optional().or(z.literal("")),
  currency: z.enum(["PKR", "AED"]),
  branch_id: z.string().uuid("Select a branch").optional().or(z.literal("")),
});

export default function NewAccount() {
  const nav = useNavigate();
  const { role, profile } = useAuth();
  const [branches, setBranches] = useState<any[]>([]);
  const [busy, setBusy] = useState(false);
  const [form, setForm] = useState({ name: "", mobile: "", address: "", currency: "PKR" as "PKR" | "AED", branch_id: "" });

  useEffect(() => {
    supabase.from("branches").select("id, name").order("name").then(({ data }) => {
      setBranches(data ?? []);
      // Auto-select user's branch if they have one
      if (profile?.branch_id) {
        setForm((f) => ({ ...f, branch_id: profile.branch_id! }));
      }
    });
  }, [profile]);

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    const parsed = schema.safeParse(form);
    if (!parsed.success) { toast.error(parsed.error.issues[0].message); return; }

    // Logic: Use selected branch, or fallback to user's branch
    const finalBranchId = form.branch_id || profile?.branch_id;

    if (!finalBranchId) {
      toast.error("Please select a branch or assign your user to a branch first.");
      return;
    }

    setBusy(true);
    const { data: { user } } = await supabase.auth.getUser();
    const { data, error } = await supabase.from("accounts").insert([{
      account_no: "",
      name: form.name.trim(),
      mobile: form.mobile?.trim() || null,
      address: form.address?.trim() || null,
      currency: form.currency,
      branch_id: finalBranchId,
      created_by: user?.id,
    }]).select("id, account_no").single();

    setBusy(false);
    if (error) { toast.error(error.message); return; }
    toast.success(`Account ${data?.account_no} created`);
    nav(`/accounts/${data?.id}`);
  };

  return (
    <div className="p-4 md:p-8 max-w-3xl mx-auto space-y-6">
      <Link to="/accounts" className="inline-flex items-center text-sm text-muted-foreground hover:text-foreground"><ArrowLeft className="w-4 h-4 mr-1" /> Back</Link>
      <div>
        <div className="text-xs uppercase tracking-wider text-muted-foreground">Create</div>
        <h1 className="font-display text-3xl md:text-4xl font-bold">New Account</h1>
        <p className="text-muted-foreground text-sm mt-1">A unique account number will be generated automatically.</p>
      </div>

      <Card className="glass p-6">
        <form onSubmit={submit} className="space-y-5">
          <div className="grid md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <Label>Name *</Label>
              <Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Customer or vendor name" required />
            </div>
            <div className="space-y-1.5">
              <Label>Mobile</Label>
              <Input value={form.mobile} onChange={(e) => setForm({ ...form, mobile: e.target.value })} placeholder="Optional" />
            </div>
          </div>

          <div className="space-y-1.5">
            <Label>Address</Label>
            <Textarea value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })} placeholder="Optional" rows={3} />
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <Label>Currency *</Label>
              <Select value={form.currency} onValueChange={(v: any) => setForm({ ...form, currency: v })}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="PKR">PKR — Pakistani Rupee</SelectItem>
                  <SelectItem value="AED">AED — UAE Dirham</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1.5">
              <Label>Branch {role === "admin" ? "(Optional)" : ""}</Label>
              <Select value={form.branch_id} onValueChange={(v) => setForm({ ...form, branch_id: v })}>
                <SelectTrigger>
                  <SelectValue placeholder={branches.length ? "Select branch (Default: Current)" : "No branches yet"} />
                </SelectTrigger>
                <SelectContent>
                  {branches.map((b) => <SelectItem key={b.id} value={b.id}>{b.name}</SelectItem>)}
                </SelectContent>
              </Select>
              {role === "admin" && !form.branch_id && profile?.branch_id && (
                <p className="text-[10px] text-muted-foreground mt-1">Defaulting to your branch: {branches.find(b => b.id === profile.branch_id)?.name}</p>
              )}
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <Button type="submit" disabled={busy} className="gradient-primary text-primary-foreground shadow-soft">{busy ? "Saving..." : "Create account"}</Button>
            <Link to="/accounts"><Button type="button" variant="ghost">Cancel</Button></Link>
          </div>
        </form>
      </Card>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate, Link, useSearchParams } from "react-router-dom";
import { toast } from "sonner";
import { ArrowLeft } from "lucide-react";
import { z } from "zod";

const schema = z.object({
  account_id: z.string().uuid("Select an account"),
  txn_date: z.string().min(1),
  details: z.string().trim().min(2).max(300),
  debit: z.number().min(0),
  credit: z.number().min(0),
}).refine((d) => d.debit > 0 || d.credit > 0, { message: "Enter debit or credit amount" });

export default function NewTransaction() {
  const nav = useNavigate();
  const [params] = useSearchParams();
  const [accounts, setAccounts] = useState<any[]>([]);
  const [busy, setBusy] = useState(false);
  const [form, setForm] = useState({
    account_id: params.get("account") ?? "",
    txn_date: new Date().toISOString().slice(0, 10),
    details: "",
    debit: "",
    credit: "",
  });

  useEffect(() => {
    supabase.from("accounts").select("id, account_no, name, currency").order("name").then(({ data }) => setAccounts(data ?? []));
  }, []);

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    const debit = Number(form.debit || 0);
    const credit = Number(form.credit || 0);
    const parsed = schema.safeParse({ ...form, debit, credit });
    if (!parsed.success) { toast.error(parsed.error.issues[0].message); return; }
    setBusy(true);
    const { data: { user } } = await supabase.auth.getUser();
    const { data, error } = await supabase.from("transactions").insert([{
      txn_code: "",
      account_id: form.account_id,
      txn_date: form.txn_date,
      details: form.details.trim(),
      debit, credit,
      created_by: user?.id,
    }]).select("id, txn_code, account_id").single();
    setBusy(false);
    if (error) { toast.error(error.message); return; }
    toast.success(`${data?.txn_code} recorded`);
    nav(`/accounts/${data?.account_id}`);
  };

  return (
    <div className="p-4 md:p-8 max-w-3xl mx-auto space-y-6">
      <Link to="/transactions" className="inline-flex items-center text-sm text-muted-foreground hover:text-foreground"><ArrowLeft className="w-4 h-4 mr-1" /> Back</Link>
      <div>
        <div className="text-xs uppercase tracking-wider text-muted-foreground">Record</div>
        <h1 className="font-display text-3xl md:text-4xl font-bold">New Transaction</h1>
      </div>

      <Card className="glass p-6">
        <form onSubmit={submit} className="space-y-5">
          <div className="space-y-1.5">
            <Label>Account *</Label>
            <Select value={form.account_id} onValueChange={(v) => setForm({ ...form, account_id: v })}>
              <SelectTrigger><SelectValue placeholder={accounts.length ? "Select account" : "No accounts yet"} /></SelectTrigger>
              <SelectContent>
                {accounts.map((a) => <SelectItem key={a.id} value={a.id}>{a.account_no} — {a.name} ({a.currency})</SelectItem>)}
              </SelectContent>
            </Select>
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <Label>Date *</Label>
              <Input type="date" value={form.txn_date} onChange={(e) => setForm({ ...form, txn_date: e.target.value })} />
            </div>
          </div>

          <div className="space-y-1.5">
            <Label>Details *</Label>
            <Textarea value={form.details} onChange={(e) => setForm({ ...form, details: e.target.value })} rows={3} placeholder="Description / narration" />
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <Label>Debit</Label>
              <Input type="number" step="0.01" min="0" value={form.debit} onChange={(e) => setForm({ ...form, debit: e.target.value })} placeholder="0.00" />
            </div>
            <div className="space-y-1.5">
              <Label>Credit</Label>
              <Input type="number" step="0.01" min="0" value={form.credit} onChange={(e) => setForm({ ...form, credit: e.target.value })} placeholder="0.00" />
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <Button type="submit" disabled={busy} className="gradient-primary text-primary-foreground shadow-soft">{busy ? "Saving..." : "Record transaction"}</Button>
            <Link to="/transactions"><Button type="button" variant="ghost">Cancel</Button></Link>
          </div>
        </form>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { FileDown, FileBarChart } from "lucide-react";
import { formatMoney, balanceLabel } from "@/lib/format";
import { exportLedgerPDF } from "@/lib/pdf";

export default function Reports() {
  const [accounts, setAccounts] = useState<any[]>([]);
  const [txns, setTxns] = useState<any[]>([]);
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");

  useEffect(() => {
    Promise.all([
      supabase.from("accounts").select("id, account_no, name, currency, branches(name)"),
      supabase.from("transactions").select("account_id, debit, credit, txn_date"),
    ]).then(([a, t]) => { setAccounts(a.data ?? []); setTxns(t.data ?? []); });
  }, []);

  const summary = useMemo(() => {
    const filteredTxns = txns.filter((t) => (!from || t.txn_date >= from) && (!to || t.txn_date <= to));
    return accounts.map((a) => {
      let debit = 0, credit = 0;
      filteredTxns.filter((t) => t.account_id === a.id).forEach((t) => { debit += Number(t.debit); credit += Number(t.credit); });
      return { ...a, debit, credit, net: credit - debit };
    });
  }, [accounts, txns, from, to]);

  return (
    <div className="p-4 md:p-8 max-w-[1600px] mx-auto space-y-6">
      <div className="flex items-center justify-between gap-3 flex-col md:flex-row">
        <div>
          <div className="text-xs uppercase tracking-wider text-muted-foreground">Insights</div>
          <h1 className="font-display text-3xl md:text-4xl font-bold flex items-center gap-2">
            <FileBarChart className="w-7 h-7 text-primary" /> Reports
          </h1>
        </div>
        <Button onClick={() => exportLedgerPDF(summary)} className="gradient-primary text-primary-foreground shadow-soft"><FileDown className="w-4 h-4 mr-1" /> Export Ledger PDF</Button>
      </div>

      <Card className="glass p-4 grid md:grid-cols-2 gap-3">
        <div><Label className="text-xs text-muted-foreground">From</Label><Input type="date" value={from} onChange={(e) => setFrom(e.target.value)} /></div>
        <div><Label className="text-xs text-muted-foreground">To</Label><Input type="date" value={to} onChange={(e) => setTo(e.target.value)} /></div>
      </Card>

      <Card className="glass overflow-hidden">
        <div className="p-4 border-b border-border/50">
          <h2 className="font-display font-semibold">All Accounts Summary</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-muted/40">
              <tr className="text-xs text-muted-foreground uppercase tracking-wider">
                <th className="text-left font-medium px-4 py-3">Account No</th>
                <th className="text-left font-medium px-4 py-3">Name</th>
                <th className="text-left font-medium px-4 py-3 hidden md:table-cell">Branch</th>
                <th className="text-left font-medium px-4 py-3">Cur</th>
                <th className="text-right font-medium px-4 py-3">Debit</th>
                <th className="text-right font-medium px-4 py-3">Credit</th>
                <th className="text-right font-medium px-4 py-3">Net</th>
              </tr>
            </thead>
            <tbody>
              {summary.length === 0 ? (
                <tr><td colSpan={7} className="text-center py-12 text-muted-foreground text-sm">No data.</td></tr>
              ) : summary.map((r) => (
                <tr key={r.id} className="border-t border-border/50 hover:bg-muted/30">
                  <td className="px-4 py-2.5 font-mono text-xs">{r.account_no}</td>
                  <td className="px-4 py-2.5 font-medium">{r.name}</td>
                  <td className="px-4 py-2.5 hidden md:table-cell text-muted-foreground">{r.branches?.name ?? "—"}</td>
                  <td className="px-4 py-2.5"><Badge variant="secondary" className="font-mono text-xs">{r.currency}</Badge></td>
                  <td className="px-4 py-2.5 text-right num text-destructive">{formatMoney(r.debit, r.currency)}</td>
                  <td className="px-4 py-2.5 text-right num text-success">{formatMoney(r.credit, r.currency)}</td>
                  <td className={`px-4 py-2.5 text-right num font-semibold ${r.net >= 0 ? "text-success" : "text-destructive"}`}>
                    {formatMoney(r.net, r.currency)} <span className="text-xs">{balanceLabel(r.net)}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Plus, Search } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { Link } from "react-router-dom";
import { Skeleton } from "@/components/ui/skeleton";
import { formatMoney } from "@/lib/format";

export default function Transactions() {
  const [rows, setRows] = useState<any[] | null>(null);
  const [q, setQ] = useState("");
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");

  useEffect(() => {
    supabase.from("transactions").select("id, txn_code, txn_date, details, debit, credit, accounts(name, account_no, currency)").order("txn_date", { ascending: false }).order("created_at", { ascending: false }).limit(500).then(({ data }) => setRows(data ?? []));
  }, []);

  const filtered = useMemo(() => (rows ?? []).filter((r) => {
    if (q && !r.txn_code.toLowerCase().includes(q.toLowerCase()) && !r.details.toLowerCase().includes(q.toLowerCase()) && !r.accounts?.name?.toLowerCase().includes(q.toLowerCase())) return false;
    if (from && r.txn_date < from) return false;
    if (to && r.txn_date > to) return false;
    return true;
  }), [rows, q, from, to]);

  return (
    <div className="p-4 md:p-8 max-w-[1600px] mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
        <div>
          <div className="text-xs uppercase tracking-wider text-muted-foreground">Activity</div>
          <h1 className="font-display text-3xl md:text-4xl font-bold">Transactions</h1>
        </div>
        <Link to="/transactions/new"><Button className="gradient-primary text-primary-foreground shadow-soft"><Plus className="w-4 h-4 mr-1" /> New Transaction</Button></Link>
      </div>

      <Card className="glass p-4 grid md:grid-cols-3 gap-3">
        <div>
          <Label className="text-xs text-muted-foreground">Search</Label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Code, account, details…" className="pl-10" />
          </div>
        </div>
        <div><Label className="text-xs text-muted-foreground">From</Label><Input type="date" value={from} onChange={(e) => setFrom(e.target.value)} /></div>
        <div><Label className="text-xs text-muted-foreground">To</Label><Input type="date" value={to} onChange={(e) => setTo(e.target.value)} /></div>
      </Card>

      {!rows ? (
        <div className="grid gap-2">{[...Array(5)].map((_, i) => <Skeleton key={i} className="h-12" />)}</div>
      ) : (
        <Card className="glass overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-muted/40">
                <tr className="text-xs text-muted-foreground uppercase tracking-wider">
                  <th className="text-left font-medium px-4 py-3">Date</th>
                  <th className="text-left font-medium px-4 py-3">Code</th>
                  <th className="text-left font-medium px-4 py-3">Account</th>
                  <th className="text-left font-medium px-4 py-3 hidden md:table-cell">Details</th>
                  <th className="text-right font-medium px-4 py-3">Debit</th>
                  <th className="text-right font-medium px-4 py-3">Credit</th>
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan={6} className="text-center py-12 text-muted-foreground text-sm">No transactions match.</td></tr>
                ) : filtered.map((t: any) => (
                  <tr key={t.id} className="border-t border-border/50 hover:bg-muted/30">
                    <td className="px-4 py-2.5 num">{t.txn_date}</td>
                    <td className="px-4 py-2.5 font-mono text-xs">{t.txn_code}</td>
                    <td className="px-4 py-2.5">
                      <div className="font-medium">{t.accounts?.name}</div>
                      <div className="text-xs text-muted-foreground font-mono">{t.accounts?.account_no}</div>
                    </td>
                    <td className="px-4 py-2.5 hidden md:table-cell text-muted-foreground truncate max-w-md">{t.details}</td>
                    <td className="px-4 py-2.5 text-right num text-destructive">{Number(t.debit) > 0 ? formatMoney(Number(t.debit), t.accounts?.currency) : "—"}</td>
                    <td className="px-4 py-2.5 text-right num text-success">{Number(t.credit) > 0 ? formatMoney(Number(t.credit), t.accounts?.currency) : "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  );
}
